def catalan_number(n):
    # Base case: catalan(0) = 1
    if n == 0:
        return 1

    # Initialize dp array
    dp = [0] * (n + 1)
    dp[0] = 1  # catalan(0) = 1

    # Calculate catalan numbers iteratively
    for i in range(1, n + 1):
        for j in range(i):
            dp[i] += dp[j] * dp[i - j - 1]

