        if text[i:i+3] == "ly ":  # Check if the word ends with "ly "
            adverbs.append((i, i+3))
    if adverbs:
        return f"{adverbs[0][0]}-{adverbs[0][1]}: {text[adverbs[0][0]:adverbs[0][1]]}"
