    mismatch = [i for i in range(len(str1)) if str1[i] != str2[i]]
    if len(mismatch) % 2 != 0:
        return "Not Possible"
    swaps = 0
    while mismatch:
        i = mismatch.pop()
        j = mismatch.pop(0)
        str1 = str1[:i] + str1[j] + str1[i+1:j] + str1[i] + str1[j+1:]
        mismatch.remove(j)
    return swaps

def min_Swaps(X, Y):
    n = len(X)
    m = len(Y)

    # If lengths of both strings are not equal, it is impossible to convert one to the other
    if n != m:
        return "Not Possible"

    # Count the number of differing positions between the two strings
    diff_count = 0
    for i in range(n):
        if X[i] != Y[i]:
            diff_count += 1

    # If the number of differing positions is odd, it is impossible to convert one to the other
    if diff_count % 2 != 0:
        return "Not Possible"

    # Calculate the number of swaps needed
    swap_count = 0
    for i in range(n):
        if X[i] != Y[i]:
            # Find the position of the matching character in the remaining string
            for j in range(i + 1, n):
                if X[j] == Y[i]:
                    # Swap the characters and increment the swap count
                    X = X[:i] + X[j] + X[i+1:j] + X[i] + X[j+1:]
                    swap_count += 1
                    break

    return swap_count

def min_Swaps(A, B):
    if len(A) != len(B):
        return "Not Possible"
    A = list(map(int, A))
    B = list(map(int, B))
    count_a_ones = A.count(1)
    count_b_ones = B.count(1)

    if count_a_ones != count_b_ones:
        return "Not Possible"

    ones_positions = [(i, A[i]) for i in range(len(A)) if A[i] == 1]
    swaps = 0

    for i in range(len(ones_positions)):
        if ones_positions[i][1] != B[ones_positions[i][0]]:
            swaps += 1

    if swaps % 2 == 1:
        return "Not Possible"
    else:
        return swaps // 2

def min_Swaps(a, b):
    n = len(a)
    if a.count('1') != b.count('1'):
        return "Not Possible"
    temp = [(a[i], b[i]) for i in range(n)]
    temp.sort(key=lambda x: x[1])
    count = 0
    for i in range(n):
        if temp[i][1] == '0':
            continue
        j = i + 1
        while j < n and temp[j][1] == '0':
            j += 1
        if j == n:
            return "Not Possible"
        count += j - i
        for k in range(i, j + 1):
            temp[k] = ('1' if temp[k][1] == '0' else '0', temp[k][1])
    return count

def min_Swaps(x, y):
    if len(x) != len(y) or sum(x) != sum(y):
        return "Not Possible"
    x = list(x)
    y = list(y)
    count = 0
    for i in range(len(x)):
        if x[i] != y[i]:
            j = i + 1
            while j < len(x) and x[j] == y[i]:
                j += 1
            if j == len(x):
                return "Not Possible"
            x[j], x[i] = x[i], x[j]
            count += 1
    return count

