def find_kth(A, B, K):
    # If the first array is empty, return the Kth element from the second array
    if not A:
        return B[K - 1]
    # If the second array is empty, return the Kth element from the first array
    if not B:
        return A[K - 1]
    # Compare the elements at the Kth positions in both arrays
    if A[K // 2 - 1] > B[K // 2 - 1]:
        # If the element in the first array is larger, ignore the first K//2 elements of the first array
        return find_kth(A[K // 2:], B, K - K // 2)
    else:
        # If the element in the second array is larger or equal, ignore the first K//2 elements of the second array
        return find_kth(A, B[K // 2:], K - K // 2)

