    while i < len(arr1) and j < len(arr2):
        if arr1[i] <= arr2[j]:
            if k == 1:
                return arr1[i]
            i += 1
            k -= 1
        else:
            if k == 1:
                return arr2[j]
            j += 1
            k -= 1
    if i == len(arr1):
        return arr2[j + k - 1]
    return arr1[i + k - 1]

def find_kth(A, B, k):
    m, n = len(A), len(B)
    if m > n:
        A, B, m, n = B, A, n, m

    lo, hi = 0, m
    while lo <= hi:
        i = (lo + hi) // 2
        j = k - i

        if i < m and j > 0 and B[j-1] > A[i]:
            lo = i + 1
        elif i > 0 and j < n and A[i-1] > B[j]:
            hi = i - 1
        else:
            if i == 0:
                return B[j-1]
            elif j == 0:
                return A[i-1]
            else:
                return max(A[i-1], B[j-1])

def find_kth(A, B, k):
    i = j = 0
    while True:
        if i >= len(A):
            return B[j + k - 1]
        elif j >= len(B):
            return A[i + k - 1]
        elif k == 1:
            return min(A[i], B[j])
        mid_k = k // 2
        mid_i = min(i + mid_k - 1, len(A) - 1)
        mid_j = min(j + mid_k - 1, len(B) - 1)
        if A[mid_i] <= B[mid_j]:
            k -= mid_i - i + 1
            i = mid_i + 1
        else:
            k -= mid_j - j + 1
            j = mid_j + 1

def find_kth(A, B, k):
