def min_Swaps(str1, str2):
    n = len(str1)

    # If lengths of both strings are not same, then they cannot be converted to each other
    if n != len(str2):
        return "Not Possible"

    # Create a matrix where each entry matrix[i][j] will be 'True' if str1[i] is equal to str2[j]
    matrix = [[False for _ in range(n)] for _ in range(n)]

    # Build the matrix
    for i in range(n):
        for j in range(n):
            if str1[i] == str2[j]:
                matrix[i][j] = True

    # To store the length of longest increasing subsequence
    lis = [1] * n

    # Compute the LIS values in bottom up manner
    for i in range(1, n):
        for j in range(i):
            if matrix[j][i] and lis[i] < lis[j] + 1:
                lis[i] = lis[j] + 1

    # The length of the longest alternating sequence will be (n - lis[n-1])
    return n - lis[-1]

