def min_Swaps(str1, str2):
    n = len(str1)
    m = len(str2)

    # If lengths are not equal, conversion is not possible
    if n != m:
        return "Not Possible"

    # Create a matrix where each cell represents the difference between corresponding bits of str1 and str2
    diff = [[0] * (m + 1) for _ in range(n + 1)]
    for i in range(1, n + 1):
        for j in range(1, m + 1):
            diff[i][j] = int(str1[i - 1]) ^ int(str2[j - 1])

    # Build the DP table
    dp = [[0] * (m + 1) for _ in range(n + 1)]
    for i in range(1, n + 1):
        for j in range(1, m + 1):
            if diff[i][j] == 0:
                dp[i][j] = dp[i - 1][j - 1] + 1
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

    # The result is the length of the longest common subsequence
    lcs_length = dp[n][m]

    # If lcs_length is equal to n, no swaps are needed
    if lcs_length == n:
        return 0

    # Calculate the number of swaps required
    swaps = n - lcs_length
    return swaps

