def min_Swaps(str1, str2):
    if len(str1) != len(str2):
        return "Not Possible"

    n = len(str1)
    count = [0] * 2

    # Count occurrences of '0' and '1'
    for i in range(n):
        count[int(str1[i])] += 1
        count[int(str2[i])] -= 1

    # If the count of '0's is not equal to the count of '1's, it's not possible to make them equal
    if count[0] != count[1]:
        return "Not Possible"

    # Count the number of inversions needed
    swaps = 0
    i = 0
    while i < n:
        if str1[i] != str2[i]:
            j = i + 1
            # Find the position of the matching character
            while j < n and str1[j] != str2[i]:
                j += 1
            if j == n:
                return "Not Possible"
            # Swap elements to bring the matching character to its correct position
            while j > i:
                str1[j - 1], str1[j] = str1[j], str1[j - 1]
                swaps += 1
                j -= 1
        i += 1

    return swaps

