def min_Swaps(s1, s2):
    if len(s1) != len(s2) or sum(s1) != sum(s2):
        return "Not Possible"

    n = len(s1)
    m = s1.count('1')

    if n - m != s2.count('1'):
        return "Not Possible"

    dp = [[0] * (m + 1) for _ in range(n + 1)]

    for i in range(1, n + 1):
        for j in range(1, m + 1):
            if s1[i - 1] == '1' and s2[i - 1] == '0':
                dp[i][j] = dp[i - 1][j - 1] + 1
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

    if dp[n][m] % 2 != 0:
        return "Not Possible"

    return dp[n][m] // 2

