    # Traverse both arrays until k elements are found
    while i < len(arr1) and j < len(arr2):
        # Compare elements at the current pointers
        if arr1[i] < arr2[j]:
            # If arr1's element is smaller, increment the pointer for arr1
            i += 1
        else:
            # If arr2's element is smaller or equal, increment the pointer for arr2
            j += 1
        # If k elements are found, return the current element
        if k == 1:
            return min(arr1[i - 1], arr2[j - 1])
        # Decrement k as one element is included in the answer
        k -= 1
    # If all elements from one array are traversed, return the kth smallest element from the other array
