def find_kth(A, B, k):
    # Initialize pointers for both arrays
    i, j = 0, 0
    # Loop until we find the kth smallest element
    while i < len(A) and j < len(B):
        # If the current element in A is smaller or equal to the current element in B, move the pointer in A
        if A[i] <= B[j]:
            i += 1
        else:
            # Otherwise, move the pointer in B
            j += 1
    # If pointer in A has reached the end, return the (k - i)th element from B
    if i == len(A):
        return B[k - i]
    # If pointer in B has reached the end, return the (k - j)th element from A
    elif j == len(B):
        return A[k - j]
    # If neither pointer has reached the end, return the kth smallest element
    return min(A[i], B[j])

